+@MainActor
+final class SystemStatusItemHost: StatusItemHosting {
+    private let statusItem: NSStatusItem
+
+    init(statusBar: NSStatusBar = .system) {
+        statusItem = statusBar.statusItem(withLength: NSStatusItem.variableLength)
