+private final class StatusMenuActionBox: NSObject {
+    let action: StatusMenuAction
+
+    init(action: StatusMenuAction) {
+        self.action = action
+    }
+}
+
+struct StatusMenuSnapshot {
+    let isOnboardingComplete: Bool
+    let versionLabel: String
+    let statusLine: String?
+    let cleanupModelDownloadProgress: Double?
+    let menuErrorMessage: String?
+    let recoveryActions: [MenuRecoveryAction]
+
+    @MainActor
+    init(appController: AppController) {
+        isOnboardingComplete = appController.isOnboardingComplete
+        versionLabel = appController.versionLabel
+        statusLine = appController.statusLine
+        cleanupModelDownloadProgress = appController.cleanupModelDownloadProgress
+        menuErrorMessage = appController.menuErrorMessage
+        recoveryActions = appController.recoveryActions
+    }
+}
+
+private final class StatusMenuActionDispatcher: NSObject {
+    var handler: (StatusMenuAction) -> Void = { _ in }
+
+    @objc
+    func performAction(_ sender: NSMenuItem) {
+        guard
+            let actionBox = sender.representedObject as? StatusMenuActionBox
+        else {
+            return
+        }
+
+        handler(actionBox.action)
+    }
+}
+
+final class StatusMenuController: NSObject, NSMenuDelegate {
+    let menu = NSMenu()
+
+    private var snapshot: StatusMenuSnapshot
+    private let performAction: (StatusMenuAction) -> Void
+    private let prepareUpdates: () -> Void
+    private let actionDispatcher = StatusMenuActionDispatcher()
+
+    init(
+        snapshot: StatusMenuSnapshot,
+        performAction: ((StatusMenuAction) -> Void)? = nil,
+        prepareUpdates: (() -> Void)? = nil
+    ) {
+        self.snapshot = snapshot
+        self.performAction = performAction ?? { _ in }
+        self.prepareUpdates = prepareUpdates ?? {}
+        super.init()
+        actionDispatcher.handler = self.performAction
+        menu.autoenablesItems = false
+        menu.delegate = self
+        refreshMenu()
+    }
+
+    func applySnapshot(_ snapshot: StatusMenuSnapshot) {
+        self.snapshot = snapshot
+        refreshMenu()
+    }
+
+    func menuWillOpen(_ menu: NSMenu) {
+        if snapshot.isOnboardingComplete {
+            prepareUpdates()
+        }
+
+        refreshMenu()
+    }
+
+    func menuNeedsUpdate(_ menu: NSMenu) {
+        refreshMenu()
+    }
+
+    func refreshMenu() {
+        menu.removeAllItems()
+
+        if snapshot.isOnboardingComplete {
+            addActionItem("Settings...", action: .settings)
+            addActionItem("Debug Log...", action: .debugLog)
+            addInfoItem(snapshot.versionLabel)
+
+            if let statusLine = snapshot.statusLine {
+                addInfoItem(statusLine)
+            }
+
+            if let cleanupDownloadProgress = snapshot.cleanupModelDownloadProgress {
+                let progressPercent = Int((cleanupDownloadProgress * 100).rounded())
+                addInfoItem("Cleanup model download: \(progressPercent)%")
+            }
+
+            if let errorMessage = snapshot.menuErrorMessage {
+                addInfoItem(errorMessage)
+            }
+
+            for action in snapshot.recoveryActions {
+                addActionItem(action.title, action: .recovery(action))
+            }
+
+            menu.addItem(.separator())
+            addActionItem("Check for Updates", action: .checkForUpdates)
+            menu.addItem(.separator())
+        } else {
+            addActionItem("Show Setup Window", action: .showSetupWindow)
+        }
+
+        addActionItem("Quit", action: .quit, keyEquivalent: "q")
+    }
+
+    private func addActionItem(
+        _ title: String,
+        action: StatusMenuAction,
+        keyEquivalent: String = ""
+    ) {
+        let item = NSMenuItem(
+            title: title,
+            action: #selector(StatusMenuActionDispatcher.performAction(_:)),
+            keyEquivalent: keyEquivalent
+        )
+        item.target = actionDispatcher
+        item.representedObject = StatusMenuActionBox(action: action)
+        menu.addItem(item)
+    }
+
+    private func addInfoItem(_ title: String) {
+        let item = NSMenuItem(title: title, action: nil, keyEquivalent: "")
+        item.isEnabled = false
+        menu.addItem(item)
+    }
+}
