+@MainActor
+final class StatusItemController {
+    private let appController: AppController
+    private let statusItemHost: any StatusItemHosting
+    private let menuController: StatusMenuController
+    private var controllerObserver: AnyCancellable?
+
+    init(
+        appController: AppController,
+        statusItemHost: any StatusItemHosting = SystemStatusItemHost()
+    ) {
+        self.appController = appController
+        self.statusItemHost = statusItemHost
+        menuController = StatusMenuController(
+            snapshot: StatusMenuSnapshot(appController: appController),
+            performAction: appController.performStatusMenuAction,
+            prepareUpdates: appController.prepareUpdates
+        )
+        statusItemHost.menu = menuController.menu
+        syncFromController()
+        controllerObserver = appController.objectWillChange.sink { [weak self] in
+            Task { @MainActor [weak self] in
+                self?.syncFromController()
+            }
+        }
+    }
+
+    private func syncFromController() {
+        statusItemHost.image = StatusMenuIcon.makeImage(for: appController.status)
+        menuController.applySnapshot(StatusMenuSnapshot(appController: appController))
+    }
+}
